    // 9. Record recompute count after batch updates
    int countAfterBatch = recomputeCount;

    // 10. Get final sum
    int finalSum = sumCalc();

    return std::make_tuple(finalSum, countAfterNonBatch, countAfterBatch);
}

}  // namespace test_reaction
