            : CacheBase(maxSize, ttl) {}

        using CacheBase::getCachedValue;
        using CacheBase::cacheValue;
        using CacheBase::invalidateAllEntries;
        using CacheBase::getStatsInternal;
        using CacheBase::triggerCleanupInternal;
    };

