        .entriesBefore = statsBefore.totalEntries,
        .entriesAfterInsert = statsAfterInsert.totalEntries,
        .entriesAfterInvalidate = statsAfterInvalidate.totalEntries,
        .hitCount = statsAfterInvalidate.hitCount,
